mapper.select:
select *
from user_session
where user_id = #{userId}
  and device_slot = #{deviceSlot}
limit 1

mapper.update:
update app_user
set last_login_time = now()
where id = #{userId}

update app_user
set nickname   = #{nickname},
    avatar_url = #{avatarUrl}
where id = #{id}

update user_profile
set bio = #{bio}
where user_id = #{userId}

update user_privacy_setting
set allow_friend_view_profile = #{allowFriendViewProfile},
    allow_teammate_view_study = #{allowTeammateViewStudy},
    allow_stranger_message    = #{allowStrangerMessage}
where user_id = #{userId}

update user_auth
set password_hash = #{passwordHash},
    password_salt = #{passwordSalt}
where user_id = #{userId}
  and auth_type = 'email'

update app_user
set status = 4
where id = #{userId}

update user_session
set status = 0,
    logout_time = #{logoutTime}
where user_id = #{userId}
  and status = 1

mapper.delete:
delete
from user_blacklist
where user_id = #{userId}
  and blocked_user_id = #{blockedUserId}
